#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long X; scanf("%d %lld", &N, &X);
        int cntEven = 0, cntOdd = 0;
        for (int i = 0; i < N; ++i) {
            long long a; scanf("%lld", &a);
            if (a & 1LL) cntOdd++; else cntEven++;
        }
        long long ans;
        if (X & 1LL) {
            ans = (cntEven + 1) / 2; // ceil
        } else {
            if (cntOdd == 0) ans = -1;
            else ans = cntEven;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

