#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        cnt_even = cnt_odd = 0
        for _ in range(N):
            a = int(next(it))
            if a & 1:
                cnt_odd += 1
            else:
                cnt_even += 1
        if X & 1:
            ans = (cnt_even + 1) // 2
        else:
            if cnt_odd == 0:
                ans = -1
            else:
                ans = cnt_even
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

